1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const countLiveNeighbors = ([x, y]: Cell, alive: ReadonlySet<string>): number =>
12	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => alive.has(cellKey([x + dx, y + dy]))).length;
13	
14	const isAliveNextGen = (isCurrentlyAlive: boolean, neighbors: number): boolean =>
15	  neighbors === 3 || (isCurrentlyAlive && neighbors === 2);
16	
17	const candidateCells = (cells: ReadonlyArray<Cell>): Map<string, Cell> => {
18	  const candidates = new Map<string, Cell>();
19	  for (const [x, y] of cells) {
20	    for (const [dx, dy] of [[0, 0], ...NEIGHBOR_OFFSETS] as Cell[]) {
21	      const cell: Cell = [x + dx, y + dy];
22	      candidates.set(cellKey(cell), cell);
23	    }
24	  }
25	  return candidates;
26	};
27	
28	export function nextGeneration(cells: Cell[]): Cell[] {
29	  const alive = new Set(cells.map(cellKey));
30	  return [...candidateCells(cells).values()].filter((cell) =>
31	    isAliveNextGen(alive.has(cellKey(cell)), countLiveNeighbors(cell, alive)),
32	  );
33	}
